def merge_unique(rows):
    seen = {}
    conflicts = []
    for r in rows:
        i = r["id"]
        if i in seen and seen[i] != r:
            conflicts.append(i)
        seen[i] = r
    return list(seen.values()), conflicts
print(merge_unique([{"id": "A", "v": 1}, {"id": "A", "v": 2}, {"id": "B", "v": 1}]))
